6485     ConstantInt *CaseVal = I.getCaseValue();
6486 
6487     // Resulting value at phi nodes for this case value.
6488     SwitchCaseResultsTy Results;
6489     if (!getCaseResults(SI, CaseVal, I.getCaseSuccessor(), &CommonDest, Results,
6490                         DL, TTI))
